static Document parseByteData(ByteBuffer byteData, String charsetName, String baseUri, Parser parser) {
    String docData;
    Document doc = null;
    if (charsetName == null) { // determine from meta. safe parse as UTF-8
        // look for <meta http-equiv="Content-Type" content="text/html;charset=gb2312"> or HTML5 <meta charset="gb2312">
        Charset initialCharset = Charset.forName(defaultCharset);
        docData = decodeWithBomHandling(byteData, initialCharset);
        doc = parser.parseInput(docData, baseUri);
        Element meta = doc.select("meta[http-equiv=content-type], meta[charset]").first();
        if (meta != null) { // if not found, will keep utf-8 as best attempt
            String foundCharset = meta.hasAttr("http-equiv") ? getCharsetFromContentType(meta.attr("content")) : meta.attr("charset");
            if (foundCharset != null && !foundCharset.trim().isEmpty() && !foundCharset.equalsIgnoreCase(defaultCharset)) { // need to re-decode
                Charset newCharset = Charset.forName(foundCharset);
                if (!newCharset.equals(initialCharset)) {
                    byteData.rewind();
                    docData = decodeWithBomHandling(byteData, newCharset);
                    doc = null;
                }
            }
        }
    } else { // specified by content type header (or by user on file load)
        Validate.notEmpty(charsetName, "Must set charset arg to character set of file to parse. Set to null to attempt to detect from HTML");
        Charset specifiedCharset = Charset.forName(charsetName);
        docData = decodeWithBomHandling(byteData, specifiedCharset);
    }
    if (doc == null) {
        doc = parser.parseInput(docData, baseUri);
        doc.outputSettings().charset(charsetName);
    }
    return doc;
}

private static String decodeWithBomHandling(ByteBuffer byteData, Charset charset) {
    ByteBuffer buffer = byteData.slice();
    String bom = "\uFEFF";
    String decoded = charset.decode(buffer).toString();
    if (decoded.startsWith(bom)) {
        return decoded.substring(bom.length());
    }
    return decoded;
}

