private static String removeBom(String str, String charsetName) {
    if (str == null || str.isEmpty()) {
        return str;
    }
    if (charsetName.equalsIgnoreCase("UTF-8") && str.charAt(0) == '﻿') {
        return str.substring(1);
    } else if (charsetName.equalsIgnoreCase("UTF-16BE") && str.startsWith("\uFEFF")) {
        return str.substring(1);
    } else if (charsetName.equalsIgnoreCase("UTF-16LE") && str.startsWith("\uFFFE")) {
        return str.substring(1);
    }
    return str;
}

