private static String removeBom(String str) {
    if (str.startsWith("\uFEFF")) {
        return str.substring(1);
    }
    if (str.startsWith("\uFFFE")) {
        return str.substring(1);
    }
    if (str.startsWith("\uFEFF\u0000")) {
        return str.substring(2);
    }
    if (str.startsWith("\u0000\uFEFF")) {
        return str.substring(2);
    }
    if (str.startsWith("\uFEFF\u0000\u0000\u0000")) {
        return str.substring(4);
    }
    if (str.startsWith("\u0000\u0000\uFEFF\u0000")) {
        return str.substring(4);
    }
    return str;
}

