private static String removeBOM(String data) {
    if (data.startsWith("\uFEFF")) { // UTF-8 BOM
        return data.substring(1);
    } else if (data.startsWith("\uFFFE\u0000") || data.startsWith("\u0000\uFFFE")) { // UTF-16 BOM
        return data.substring(2);
    } else if (data.startsWith("\uFEFF\u0000\u0000\u0000") || data.startsWith("\u0000\u0000\uFEFF\u0000")) { // UTF-32 BOM
        return data.substring(4);
    }
    return data;
}

